-- 19.1 Thong ke tien do va file theo du an
SELECT
    da.MaDuAn,
    da.TenDuAn,
    COUNT(DISTINCT ct.MaChiTietCV) AS SoChiTiet,
    COUNT(DISTINCT td.MaTienDo) AS SoBaoCaoTienDo,
    SUM(CASE WHEN td.TrangThaiTienDo = N'DaDuyet' THEN 1 ELSE 0 END) AS SoBaoCaoDaDuyet,
    SUM(CASE WHEN td.TrangThaiTienDo = N'TuChoi' THEN 1 ELSE 0 END) AS SoBaoCaoTuChoi,
    SUM(CASE WHEN td.TrangThaiTienDo = N'YeuCauBoSung' THEN 1 ELSE 0 END) AS SoBaoCaoYeuCauBoSung,
    SUM(CASE WHEN td.TrangThaiTienDo = N'ChoDuyet' THEN 1 ELSE 0 END) AS SoBaoCaoChoDuyet,
    COUNT(DISTINCT f.MaFileTDCV) AS SoFileTienDo
FROM [dbo].[DU_AN] da
JOIN [dbo].[DANH_MUC_CONG_VIEC] dm ON dm.MaDuAn = da.MaDuAn
JOIN [dbo].[CONG_VIEC] cv ON cv.MaDanhMucCV = dm.MaDanhMucCV
JOIN [dbo].[CT_CONG_VIEC] ct ON ct.MaCongViec = cv.MaCongViec
LEFT JOIN [dbo].[TIEN_DO_CONG_VIEC] td ON td.MaChiTietCV = ct.MaChiTietCV
LEFT JOIN [dbo].[FILE_TIEN_DO_CONG_VIEC] f ON f.MaTienDo = td.MaTienDo AND f.IsDeleted = 0
WHERE da.MaDuAn BETWEEN 1 AND 10
GROUP BY da.MaDuAn, da.TenDuAn
ORDER BY da.MaDuAn;
GO

-- 19.2 Bao cao tien do chua co file dinh kem
SELECT td.MaTienDo, td.MaChiTietCV, td.MaNguoiDung, td.TrangThaiTienDo
FROM [dbo].[TIEN_DO_CONG_VIEC] td
LEFT JOIN [dbo].[FILE_TIEN_DO_CONG_VIEC] f ON f.MaTienDo = td.MaTienDo AND f.IsDeleted = 0
WHERE f.MaFileTDCV IS NULL
ORDER BY td.MaTienDo;
GO

-- 19.3 Bao cao bi tu choi hoac yeu cau bo sung nhung khong co bao cao sau do
SELECT td.MaTienDo, td.MaChiTietCV, td.TrangThaiTienDo, td.ThoiGianCapNhat
FROM [dbo].[TIEN_DO_CONG_VIEC] td
WHERE td.TrangThaiTienDo IN (N'TuChoi', N'YeuCauBoSung')
  AND NOT EXISTS (
      SELECT 1
      FROM [dbo].[TIEN_DO_CONG_VIEC] td2
      WHERE td2.MaChiTietCV = td.MaChiTietCV
        AND td2.ThoiGianCapNhat > td.ThoiGianCapNhat
  )
ORDER BY td.MaChiTietCV, td.ThoiGianCapNhat;
GO

-- 19.4 Nguoi cap nhat tien do nam ngoai du an
SELECT td.MaTienDo, da.MaDuAn, da.TenDuAn, td.MaNguoiDung, nd.HoTen
FROM [dbo].[TIEN_DO_CONG_VIEC] td
JOIN [dbo].[CT_CONG_VIEC] ct ON ct.MaChiTietCV = td.MaChiTietCV
JOIN [dbo].[CONG_VIEC] cv ON cv.MaCongViec = ct.MaCongViec
JOIN [dbo].[DANH_MUC_CONG_VIEC] dm ON dm.MaDanhMucCV = cv.MaDanhMucCV
JOIN [dbo].[DU_AN] da ON da.MaDuAn = dm.MaDuAn
JOIN [dbo].[NGUOI_DUNG] nd ON nd.MaNguoiDung = td.MaNguoiDung
WHERE NOT EXISTS (
    SELECT 1
    FROM [dbo].[NHAN_VIEN_DU_AN] nvda
    WHERE nvda.MaDuAn = da.MaDuAn
      AND nvda.MaNguoiDung = td.MaNguoiDung
)
ORDER BY da.MaDuAn, td.MaTienDo;
GO

-- 19.5 Du an hoan thanh tre so voi ngay ket thuc du kien
SELECT
    da.MaDuAn,
    da.TenDuAn,
    da.NgayKetThucDuAn,
    da.NgayHoanThanhThucTeDuAn,
    DATEDIFF(DAY, da.NgayKetThucDuAn, da.NgayHoanThanhThucTeDuAn) AS SoNgayTre,
    da.TrangThaiDuAn,
    da.PhanTramHoanThanh
FROM [dbo].[DU_AN] da
WHERE da.MaDuAn BETWEEN 1 AND 10
ORDER BY da.MaDuAn;
GO

-- 19.6 Yeu cau doi quan ly du an
SELECT yc.MaYeuCauDoiQuanLy, yc.MaDuAn, da.TenDuAn, yc.MaQuanLyHienTai, qlht.HoTen AS TenQuanLyHienTai, yc.MaQuanLyDeXuat, qldx.HoTen AS TenQuanLyDeXuat, yc.TrangThaiYeuCauDoiQuanLy, yc.NgayTaoYeuCauDoiQuanLy, yc.NgayDuyetYeuCauDoiQuanLy
FROM [dbo].[YEU_CAU_DOI_QUAN_LY] yc
JOIN [dbo].[DU_AN] da ON da.MaDuAn = yc.MaDuAn
JOIN [dbo].[NGUOI_DUNG] qlht ON qlht.MaNguoiDung = yc.MaQuanLyHienTai
JOIN [dbo].[NGUOI_DUNG] qldx ON qldx.MaNguoiDung = yc.MaQuanLyDeXuat
WHERE yc.MaDuAn BETWEEN 1 AND 10
ORDER BY yc.MaYeuCauDoiQuanLy;
GO

-- 19.7 Nhat ky thay doi phu trach du an
SELECT nk.MaNhatKyPTDA, nk.MaDuAn, da.TenDuAn, nk.MaNguoiDung, nd.HoTen, nk.NkHanhDongPTDA, nk.NkThoiGianPTDA
FROM [dbo].[NHAT_KY_PHU_TRACH_DU_AN] nk
JOIN [dbo].[DU_AN] da ON da.MaDuAn = nk.MaDuAn
JOIN [dbo].[NGUOI_DUNG] nd ON nd.MaNguoiDung = nk.MaNguoiDung
WHERE nk.MaNhatKyPTDA >= 53
ORDER BY nk.MaNhatKyPTDA;
GO
